import{bQ as d,aL as a,u as e,G as r}from"./chunks/framework.D06dwy5q.js";const c=JSON.parse('{"title":"常见技术栈","description":"","frontmatter":{},"headers":[],"relativePath":"00.互联网与架构基础/13-常见技术栈.md","filePath":"00.互联网与架构基础/13-常见技术栈.md","lastUpdated":null}'),h={name:"00.互联网与架构基础/13-常见技术栈.md"};function o(i,t,n,l,p,b){return a(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="常见技术栈" tabindex="-1">常见技术栈 <a class="header-anchor" href="#常见技术栈" aria-label="Permalink to &quot;常见技术栈&quot;">​</a></h1><p>一个系统会用到很多工具。刚开始看这些名字很容易乱：Vue、React、FastAPI、Spring Boot、MySQL、Redis、Kafka、Nginx、Prometheus、Grafana。把它们按位置放好，就清楚很多。</p><p>技术栈就是一套常用组合：页面用什么写，接口用什么写，数据放哪里，文件放哪里，请求从哪里进来，出问题去哪里看。</p><h2 id="一、页面这一层" tabindex="-1">一、页面这一层 <a class="header-anchor" href="#一、页面这一层" aria-label="Permalink to &quot;一、页面这一层&quot;">​</a></h2><p>前端负责页面结构、样式、交互和接口调用。</p><p>常见选择：</p><table tabindex="0"><thead><tr><th>类型</th><th>常见选择</th><th>说明</th></tr></thead><tbody><tr><td>基础页面</td><td>HTML、CSS、JavaScript</td><td>静态页面、小工具、后台简单页</td></tr><tr><td>框架</td><td>Vue、React、Angular</td><td>复杂交互和组件化开发</td></tr><tr><td>构建工具</td><td>Vite、Webpack</td><td>把源码打包成浏览器可加载的文件</td></tr><tr><td>UI 组件</td><td>Element Plus、Ant Design、Naive UI</td><td>表单、表格、弹窗、导航等组件</td></tr></tbody></table><p>内部平台常见 Vue 或 React。轻量页面也可以只用原生 HTML、CSS、JavaScript。前端最终通常会变成静态文件，发布到 Nginx、对象存储或 CDN。</p><h2 id="二、接口这一层" tabindex="-1">二、接口这一层 <a class="header-anchor" href="#二、接口这一层" aria-label="Permalink to &quot;二、接口这一层&quot;">​</a></h2><p>后端负责 HTTP 接口、业务逻辑、认证权限、数据库读写和外部系统调用。</p><p>常见语言和框架：</p><table tabindex="0"><thead><tr><th>语言</th><th>常见框架</th><th>常见场景</th></tr></thead><tbody><tr><td>Java</td><td>Spring Boot、Spring Cloud</td><td>企业业务系统、微服务</td></tr><tr><td>Python</td><td>FastAPI、Django、Flask</td><td>运维平台、数据处理、内部工具</td></tr><tr><td>Go</td><td>标准库 HTTP、Gin、Fiber</td><td>云原生组件、网关、运维工具</td></tr><tr><td>Node.js</td><td>Express、NestJS</td><td>BFF、前端团队配套服务、轻量 API</td></tr></tbody></table><p>语言选择和团队背景关系很大。Java 生态完整，Python 写内部工具快，Go 部署简单且适合并发服务，Node.js 和前端生态衔接紧。落地时还要看团队能不能长期维护、排查和发布。</p><h2 id="三、数据这一层" tabindex="-1">三、数据这一层 <a class="header-anchor" href="#三、数据这一层" aria-label="Permalink to &quot;三、数据这一层&quot;">​</a></h2><p>数据库保存系统状态。</p><table tabindex="0"><thead><tr><th>类型</th><th>常见选择</th><th>适合内容</th></tr></thead><tbody><tr><td>关系型数据库</td><td>MySQL、PostgreSQL</td><td>用户、订单、权限、审计、配置</td></tr><tr><td>文档数据库</td><td>MongoDB</td><td>文档结构变化较多的数据</td></tr><tr><td>缓存 / 键值</td><td>Redis</td><td>热点数据、会话、排行榜、分布式锁</td></tr><tr><td>搜索引擎</td><td>Elasticsearch、OpenSearch</td><td>日志检索、全文搜索</td></tr></tbody></table><p>MySQL 和 PostgreSQL 都很常见。MySQL 在传统 Web 系统和国内业务里很多；PostgreSQL 在复杂 SQL、JSON、GIS、扩展能力上很强。MongoDB 更适合文档模型，Redis 更常放在缓存和状态加速的位置。</p><h2 id="四、缓存和消息" tabindex="-1">四、缓存和消息 <a class="header-anchor" href="#四、缓存和消息" aria-label="Permalink to &quot;四、缓存和消息&quot;">​</a></h2><p>缓存通常放在数据库前面，减少重复查询。Redis 是常见选择，常用于接口缓存、会话、计数器、限流、分布式锁。</p><p>消息队列通常放在服务之间，让耗时任务异步执行，或者把突发流量慢慢消费掉。</p><table tabindex="0"><thead><tr><th>消息系统</th><th>常见场景</th></tr></thead><tbody><tr><td>RabbitMQ</td><td>传统业务队列、任务分发、可靠投递</td></tr><tr><td>Kafka</td><td>日志流、事件流、大吞吐数据管道</td></tr><tr><td>Redis Stream / List</td><td>轻量队列、内部小任务</td></tr></tbody></table><p>消息队列引入后，接口返回成功不一定代表后续任务已经完成。任务积压、重复消费、消费失败和消息顺序都会成为新的排查对象。</p><h2 id="五、文件和对象存储" tabindex="-1">五、文件和对象存储 <a class="header-anchor" href="#五、文件和对象存储" aria-label="Permalink to &quot;五、文件和对象存储&quot;">​</a></h2><p>文件上传、图片、备份包、日志归档、构建产物都适合放对象存储。常见选择有云厂商对象存储、S3、MinIO。</p><p>对象存储按 bucket 和 object key 组织文件，通过 HTTP API 访问，适合海量文件和跨实例共享。</p><p>后端数据库里通常只保存文件元数据，例如文件名、大小、类型、归属用户、对象存储 key。实际文件内容放在对象存储里。</p><h2 id="六、入口这一层" tabindex="-1">六、入口这一层 <a class="header-anchor" href="#六、入口这一层" aria-label="Permalink to &quot;六、入口这一层&quot;">​</a></h2><p>入口层负责把外部请求送到正确服务。</p><table tabindex="0"><thead><tr><th>组件</th><th>作用</th></tr></thead><tbody><tr><td>Nginx</td><td>静态资源、反向代理、TLS、限流</td></tr><tr><td>HAProxy</td><td>高性能代理和负载均衡</td></tr><tr><td>云负载均衡</td><td>公网入口、四层/七层转发</td></tr><tr><td>Ingress / Gateway</td><td>Kubernetes HTTP/HTTPS 入口</td></tr><tr><td>API 网关</td><td>认证、路由、限流、审计、协议转换</td></tr></tbody></table><p>入口层经常是故障第一现场。用户报 502、504、404、证书错误、跨域错误时，入口日志和转发配置通常要看。</p><h2 id="七、看见和发布" tabindex="-1">七、看见和发布 <a class="header-anchor" href="#七、看见和发布" aria-label="Permalink to &quot;七、看见和发布&quot;">​</a></h2><p>常见可观测组合：</p><table tabindex="0"><thead><tr><th>能力</th><th>常见选择</th></tr></thead><tbody><tr><td>指标</td><td>Prometheus、VictoriaMetrics</td></tr><tr><td>看板</td><td>Grafana</td></tr><tr><td>告警</td><td>Alertmanager、Nightingale</td></tr><tr><td>日志</td><td>Loki、ELK、OpenSearch</td></tr><tr><td>链路追踪</td><td>OpenTelemetry、Jaeger、Tempo</td></tr></tbody></table><p>常见发布组合：</p><table tabindex="0"><thead><tr><th>能力</th><th>常见选择</th></tr></thead><tbody><tr><td>代码仓库</td><td>GitLab、GitHub、Gitea</td></tr><tr><td>CI</td><td>GitLab CI、Jenkins、GitHub Actions</td></tr><tr><td>镜像仓库</td><td>Harbor、云镜像仓库</td></tr><tr><td>CD / GitOps</td><td>Argo CD、Flux</td></tr></tbody></table><p>技术栈的重点是各层能接起来：代码能构建，镜像能保存，服务能部署，入口能访问，数据能保存，指标和日志能看到，故障能回滚。</p>',36)])])}const u=d(h,[["render",o]]);export{c as __pageData,u as default};
